var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이게 전부인가요?","JPN":"これで終わりですか？","ENG":"Is that all?","TWN":"這就完了嗎？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"큰소리친 것에 비해선, 그냥 그런저런 수준이로군요.","JPN":"大口を叩いていた割には、そう大したことないですね。","ENG":"Compared to all your boasting, your skills are average at best.","TWN":"吹牛吹得那麼厲害，結果也不過如此嘛。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"쳇, 너야말로 나풀나풀 도망치면서 간만 보고 있잖아.","JPN":"ちっ、あんたこそヒラヒラ逃げ回りながら様子を見てるだけじゃん。","ENG":"Tch. Says the one who keeps running away.","TWN":"嘖，你才是一直在一邊逃跑一邊觀察情況的吧。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"제대로 할 생각이 있긴 한 거야, 간잽이?","JPN":"ちゃんとやる気あんの？","ENG":"Are you even taking this seriously, you schemer?","TWN":"你到底能不能認真點？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"말씀드렸을 텐데요. 이건 훈련이 아니라, 훈육이라고요.","JPN":"言ったはずです。これは訓練ではなく、訓育だと。","ENG":"I told you beforehand. This is discipline, not training.","TWN":"我應該說過，這不是訓練，而是教導。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"훈육이든, 훈제 연어든 내가 알 바……","JPN":"訓育だか燻製だか、そんなのアタシの知ったことじゃ……","ENG":"Discipline or disco, like I care–","TWN":"我管你是教導還是教室呢，跟我有什麼……"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"으음?","JPN":"ううん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_SLASH_CLANK","slots":{"L":null,"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"크윽, 발 밑에 깔아둔 종이들이 발에 휘감겨서……!?","JPN":"くっ、足の下に敷かれた紙が足に巻きついてる……！？","ENG":"Kgh, the papers below me tangled my feet...?!","TWN":"呃，腳下的紙纏住了腳……？！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_SLASH_CLANK","slots":{"L":null,"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"제 카운터 능력이랍니다.","JPN":"私のカウンター能力です。","ENG":"This is my Counter ability.","TWN":"這是我的制裁者能力。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_SLASH_CLANK","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"CRF를 제어해서 종이를 강철처럼 단단하게 만들거나, 고무처럼 부드럽게 만들 수 있죠.","JPN":"CRFを制御して紙を鋼のように硬くしたり、ゴムのように柔らかくすることもできるんです。","ENG":"I am able to control the CRF to make paper as hard as steel or as soft as rubber.","TWN":"透過控制CRF，可以讓紙張像鋼鐵一樣堅硬，或者像橡膠一樣柔軟。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_SLASH_CLANK","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"또한 형태가 자유로운 종이라면…….","JPN":"さらに、形が自由な紙なら……","ENG":"Also, since the paper can be freely reformed...","TWN":"如果是形狀多變的紙張……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_SLASH_CLANK","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이런 식으로도 활용할 수 있습니다.","JPN":"こんな風にも活用できます。","ENG":"I am capable of utilizing it like this.","TWN":"也可以這樣利用。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_SLASH_CLANK","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"종이를 뭉쳐서… 검을 만들었어……?","JPN":"紙をひとかたまりにして……剣を作った……？","ENG":"You bunched up some paper... and turned it into a sword...?","TWN":"把紙揉成團……做成了劍……？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"큭. 비겁하게 멀리서 쏘아대면, 가까이 갈 수가 없잖아!","JPN":"くっ。卑怯だね。遠くから撃つなんて、近づけないじゃん！","ENG":"Kgh. How am I supposed to get close to you if you keep cowardly shooting from afar?!","TWN":"喂！你要是一直躲在遠處偷偷放冷槍，我怎麼靠近得了你啊！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기억하세요. 이건 비겁한 게 아니라, CRF 제어에 따른 능력 활용이라는 겁니다.","JPN":"覚えておきなさい。これは卑怯なことではなく、CRF制御による能力の活用なのです。","ENG":"Remember. This is not cowardice, but my controlling the CRF according to my ability.","TWN":"記住，這不是放冷槍，而是根據CRF控制來解放能力。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신에 관해서는 전부 읽었습니다, 시스터 루퍼.","JPN":"あなたに関する資料は全部読みました、シスター・ルーパー。","ENG":"Sister Looper, I have read everything about you.","TWN":"我說過，關於你的一切我都了解過了，洛珀姊妹。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"당신의 카운터 능력은 워치에서 전기톱 형태의 무기를 만들어내는 것.","JPN":"あなたのカウンター能力はウォッチからチェーンソー形態の武器を作り出すこと。","ENG":"Your Counter ability is manifesting an electric chainsaw-like weapon from your Watch.","TWN":"你的制裁者能力是從能量環中製造出電鋸形態的武器。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"틀림없이 당신이 자주 보던 불경한 영상물이 카운터 능력 발현의 트리거로 작용했겠죠.","JPN":"きっとあなたがよく見ていた不敬な映像が、カウンター能力発現のトリガーになったのでしょう。","ENG":"I have no doubt those blasphemous videos you frequently enjoy acted as a trigger for your Counter ability manifestation.","TWN":"毫無疑問，你經常觀看那些不入流的影片，這些影片肯定成為了觸發你制裁者能力的來源。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"시끄러워……!!","JPN":"うるさい……！！","ENG":"Shut up...!!","TWN":"閉嘴……！！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"확실히. 전기톱의 궤적이 그럭저럭 급소를 향하고 있군요.","JPN":"確かに。チェーンソーの軌跡がまあまあ急所を狙ってはいますね。","ENG":"Surely, the chainsaw's trajectory is roughly aimed at a vital point.","TWN":"確實，電鋸的軌跡還算準確地指向了要害。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"CRF로 향상된 신체 능력과 전기톱을 무기로 사용하는 저돌적인 근접 전투…….","JPN":"CRFにより向上された身体能力とチェーンソーを武器として使用する猪突猛進な近接戦闘……","ENG":"Daring close-quarter combat with physical abilities enhanced by CRF with a chainsaw as your weapon...","TWN":"透過CRF提升身體能力，以電鋸為武器，魯莽近戰……"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"이 정도 위력이라면, 일반적인 침식체의 갑피를 절단하는 데는 큰 문제가 없을 겁니다.","JPN":"これほどの威力なら、一般的な侵食体の甲皮を切断することは問題ないでしょう。","ENG":"With this amount of power, you will have no trouble cutting through the armor of a typical C.O.","TWN":"這種威力的話，切斷一般的侵蝕體外殼應該沒什麼問題。"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"However...","TWN":"但是……"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":null}}}]`);export{e as default};